  'dev.service1Desc': { en: 'Premium plugins tailored to your server needs — from minigames to core systems.', tr: 'Sunucu ihtiyaçlarınıza göre hazırlanmış premium eklentiler — mini oyunlardan çekirdek sistemlere.', ru: 'Премиум плагины под нужды вашего сервера — от мини-игр до основных систем.' },
  'dev.service2Title': { en: 'Discord Bot Development', tr: 'Discord Bot Geliştirme', ru: 'Разработка Discord ботов' },
  'dev.service2Desc': { en: 'Feature-rich bots with moderation, economy, logging, and custom command systems.', tr: 'Moderasyon, ekonomi, günlük kaydı ve özel komut sistemleri ile zengin özellikli botlar.', ru: 'Многофункциональные боты с модерацией, экономикой, логированием и системами команд.' },
  'dev.service3Title': { en: 'Website Development', tr: 'Web Sitesi Geliştirme', ru: 'Веб-разработка' },
  'dev.service3Desc': { en: 'Modern, responsive websites and web applications built with React, Next.js, and Tailwind.', tr: 'React, Next.js ve Tailwind ile oluşturulmuş modern, duyarlı web siteleri ve uygulamalar.', ru: 'Современные адаптивные сайты и веб-приложения на React, Next.js и Tailwind.' },
  'dev.service4Title': { en: 'Admin Panels', tr: 'Yönetici Panelleri', ru: 'Панели администратора' },
  'dev.service4Desc': { en: 'Full-featured admin dashboards for game servers, communities, and business tools.', tr: 'Oyun sunucuları, topluluklar ve iş araçları için tam donanımlı yönetim panelleri.', ru: 'Полнофункциональные панели управления для игровых серверов, сообществ и бизнес-инструментов.' },
  'dev.service5Title': { en: 'API Integrations', tr: 'API Entegrasyonları', ru: 'API Интеграции' },
