  'dev.service6Title': { en: 'Automation Systems', tr: 'Otomasyon Sistemleri', ru: 'Системы автоматизации' },
  'dev.service6Desc': { en: 'Custom automation tools, scheduled tasks, logging pipelines, and notification systems.', tr: 'Özel otomasyon araçları, zamanlanmış görevler, günlük kaydı ve bildirim sistemleri.', ru: 'Инструменты автоматизации, запланированные задачи, системы логирования и уведомлений.' },

